import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"寻找可信赖的模组","description":"本指南教你如何使用可信任的来源找到 Fabric 模组","frontmatter":{"title":"寻找可信赖的模组","description":"本指南教你如何使用可信任的来源找到 Fabric 模组","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_cn/1.20.4/players/finding-mods.md","filePath":"versions/1.20.4/translated/zh_cn/players/finding-mods.md","lastUpdated":1739538073000}`);var a={name:`zh_cn/1.20.4/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">寻找可信赖的模组 <a class="header-anchor" href="#h1" aria-label="Permalink to “寻找可信赖的模组”">​</a></h1><p>首先，信任是主观的，当下载模组时你应该始终根据自己的判断。 但是，有一些方法可以帮助你找到可信赖的模组。</p><h2 id="trustworthy-source" tabindex="-1">1. 使用众所周知的可信任来源 <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. 使用众所周知的可信任来源”">​</a></h2><p>大部分作者都将他们的模组发布在 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 和 <a href="https://www.curseforge.com/minecraft/search?class=mc-mods%5C&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a> 上。</p><p>这些网站会检查模组是否为他们所说的，以及是否包含恶意代码。 你还可以向那些网站举报恶意模组，他们会较快地行动。</p><h2 id="with-others" tabindex="-1">2. 与其他人讨论！ <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. 与其他人讨论！”">​</a></h2><p>如果要从并非已知可靠的来源下载模组，应该先向他人询问，看看他们是否曾从你下载的地方下载过该模组，以及他们是否遇到过任何问题。</p><p>如遇问题，欢迎在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道提问。</p><h2 id="avoid-malware" tabindex="-1">3. 避免常见的恶意网站！ <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. 避免常见的恶意网站！”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>恶意软件网站并非人人都能辨别。 如果不确定，应征求他人的意见，或避免使用该网站，只依靠值得信赖的来源，例如 Modrinth 和 CurseForge。</p></div><p>有很多网站声称它们收录 Minecraft 模组，但实际上只是恶意软件分发网站。 你应该尽量避免使用此类网站。</p><p>你可以使用 <a href="https://www.microsoft.com/en-us/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> 或 <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> 等杀毒软件或网站来检查下载的模组。 但是，不要完全依赖这些方法，因为有时可能不正确。</p><p>最后，如遇问题，欢迎在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道提问。</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};